UPDATE Restaurants SET Why = 'The execution is highly capable with premium proteins and a dedicated, small-batch galley that avoids the banquet feel entirely. However, it suffers the ''Static Menu Downgrade''—the menu does not rotate daily, leading to severe fatigue on a 7-night sailing.' WHERE Name = 'The Haven Restaurant' AND (Why IS NULL OR Why = '');
UPDATE Restaurants SET Why = 'While it escapes the mass-banquet penalty, the steaks rely heavily on standard broiling techniques without the artisanal execution found in 90+ tier steakhouses.' WHERE Name = 'Cagney''s Steakhouse' AND (Why IS NULL OR Why = '');
UPDATE Restaurants SET Why = 'A classic execution of heavy, butter-and-cream-forward French staples. It avoids the banquet penalty through a dedicated galley, but the menu feels slightly dated and lacks the hyper-seasonal inventiveness required for Michelin-level scores.' WHERE Name = 'Le Bistro' AND (Why IS NULL OR Why = '');
UPDATE Restaurants SET Why = 'A highly successful land-based partnership brings fresh pasta and vibrant flavors. Execution of the short rib ravioli is excellent, cooked strictly to order in a small-batch environment.' WHERE Name = 'Onda by Scarpetta' AND (Why IS NULL OR Why = '');
UPDATE Restaurants SET Why = 'A brilliant Mediterranean concept emphasizing fresh seafood and vibrant, herb-forward flavors. Avoids the heavy banquet penalty entirely by utilizing a focused, dedicated galley.' WHERE Name = 'Palomar' AND (Why IS NULL OR Why = '');
UPDATE Restaurants SET Why = 'An upgrade over standard cruise Mexican fare, with tableside guacamole and dedicated preparation. It is enjoyable and adult-focused, but maxes out in the low 80s due to the inherent ceiling of the cuisine type.' WHERE Name = 'Los Lobos' AND (Why IS NULL OR Why = '');
UPDATE Restaurants SET Why = 'The food is cooked to order directly in front of you, escaping the banquet penalty. However, the reliance on theatrical dining over culinary depth caps its potential.' WHERE Name IN ('Hasuki', 'Teppanyaki') AND (Why IS NULL OR Why = '');
UPDATE Restaurants SET Why = 'Excellent fish quality and precise knife work at the dedicated sushi bar. It is a premium, made-to-order experience that shines, held back slightly by limited menu breadth.' WHERE Name = 'Nama Sushi & Sashimi' AND (Why IS NULL OR Why = '');
UPDATE Restaurants SET Why = 'Despite the stunning 270-degree aesthetic design, this is the epitome of the ''Banquet Penalty''. It is a massive operation batch-cooking for thousands simultaneously, resulting in lukewarm plates and lowest-common-denominator seasoning.' WHERE Name = 'Hudson''s' AND (Why IS NULL OR Why = '');
UPDATE Restaurants SET Why = 'Shares the same mass-market menu as Hudson''s, suffering the exact same banquet penalty. Fares marginally better only because the smaller room acoustics lead to slightly less frantic service.' WHERE Name = 'The Commodore Room' AND (Why IS NULL OR Why = '');
UPDATE Restaurants SET Why = 'A brilliant exception to the included dining rule; food is ordered via tablet and cooked to order in small, dedicated stations rather than a massive central galley.' WHERE Name = 'Indulge Food Hall' AND (Why IS NULL OR Why = '');
UPDATE Restaurants SET Why = 'A new concept for the class, executed with intense, authentic aromatics in a dedicated galley. It avoids the mass-market watering-down of flavors that plagues many cruise Asian concepts.' WHERE Name = 'Sukhothai' AND (Why IS NULL OR Why = '');
UPDATE Restaurants SET Why = 'Tablet-based ordering allows for excellent, rapid-fire small-batch execution. The Asian-fusion tapas are heavily flavored, served hot, and avoid the traditional cruise dining room feel entirely.' WHERE Name = 'Food Republic' AND (Why IS NULL OR Why = '');
UPDATE Restaurants SET Why = 'It is a massive operation batch-cooking for thousands simultaneously, resulting in lowest-common-denominator seasoning.' WHERE Name = 'Taste' AND (Why IS NULL OR Why = '');
UPDATE Restaurants SET Why = 'The mirror image of Taste, sharing the same menu and galley. It is purely functional fuel.' WHERE Name = 'Savor' AND (Why IS NULL OR Why = '');
UPDATE Restaurants SET Why = 'The largest of the three MDRs on board, making the banquet penalty even more severe due to the sheer distance from the galley to the table.' WHERE Name = 'The Manhattan Room' AND (Why IS NULL OR Why = '');
UPDATE Restaurants SET Why = 'The brisket is genuinely smoked over hickory, wood, and pecan, which is a logistical win. The meat is good, but the sides lean slightly toward banquet-style batch production.' WHERE Name = 'Q Texas Smokehouse' AND (Why IS NULL OR Why = '');
UPDATE Restaurants SET Why = 'The weakest of the signature specialty restaurants. The pasta often suffers from poor texture, and the sauces lean heavily toward batch-cooked catering quality despite the upcharge.' WHERE Name = 'La Cucina' AND (Why IS NULL OR Why = '');
